        ];

        $controlA = 1; // Contador para "Sin_Bien_"
        $controlB = 1; // Contador para "Duplicate_"
        $seedcontrol =[]; // Para llevar un registro de los códigos que ya hemos visto

        foreach ($datas as $data)
        {
            // Evaluamos si en la coleccion existe un elemento que NO TIENE Bien Nacional
            if($data['code'] == 'NO TIENE')
            {
                // Cambiamos el NO TIENE por un numero de Control y el prefijo Sin_Bien
                $data['code'] = 'Sin_Bien_'.$controlA;

                // Guardamos en la base de datos
                NationalAsset::create($data);

                // Incrementamos la variable de control
                $controlA++;

            }elseif($data['code'] != 'NO TIENE') // Si el BN posee un codigo evaluamos lo sig
                {
                    if(in_array($data['code'], $seedcontrol)) // Evaluamos si el bien esta registrado en nuestro semilla de control
                    {
                        // Si se encuentra DUPLICADO, entonces en la seccion de observations, agregamos la nota y su antiguo BN
                        $data['observations'] = $data['observations'].' //Fue registrado con un bien duplicado, SINCERAR, antiguo bien: '.$data['code'];
                        
                        // Cambiamos el valor a Duplicate seguido de su respectivo contador
                        $data['code'] = 'Duplicate_'.$controlB;

                        // Guardamos
                        NationalAsset::create($data);

                        // Incrementamos la variable de control
                        $controlB++;

                    }else{
                        // Si el code de BN no esta duplicado procedemos a guardarlo en nuestro indice
                        $seedcontrol[] = $data['code'];

                        // guardamos
                        NationalAsset::create($data);
                    }
                }

        }
